/**
 * Image text to text pipeline using `AutoModelForImageTextToText`. This pipeline generates
 * text from a combined image and text prompt input, enabling tasks such as visual
 * question answering, image captioning with instructions, and multimodal chat.
 *
 * **Example:** Answer a question about an image w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/tiger.jpg';
 * const output = await pipe(image, 'What animal is in the image?');
 * // [{ generated_text: 'The image shows a tiger.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(image, text, generate_kwargs = {}) {

        // Prepare and process the input image
        const preparedImage = (await prepareImages(image))[0];
        const image_inputs = await this.processor(preparedImage);

        // Tokenize the text prompt
        const text_inputs = this.tokenizer(text, {
            padding: true,
            truncation: true,
        });

        // Run the model, merging text and image inputs
        const output = await this.model.generate({
            ...text_inputs,
            ...image_inputs,
            ...generate_kwargs,
        });

        // Decode the generated token ids back to text
        const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output), {
            skip_special_tokens: true,
        }).map(x => ({ generated_text: x.trim() }));

        return decoded;
    }
}

